const lead = $input.first().json;

if (!lead.tem_site || lead.site_inacessivel) {
  const nicho = lead.categoria_mapeada || 'Saúde/estética';
  const CONTEXTOS = {
    'Saúde/estética': { observacao_sem_site: 'o paciente decide pela confiança visual antes de marcar' },
    'Serviços profissionais': { observacao_sem_site: 'o cliente busca credibilidade antes de fechar um contrato' },
    'Comércio/loja física': { observacao_sem_site: 'o cliente quer ver os produtos antes de ir até a loja' },
    'Eventos/hospedagem': { observacao_sem_site: 'o cliente decide quase só pela primeira impressão visual' }
  };
  const obs = (CONTEXTOS[nicho] || CONTEXTOS['Saúde/estética']).observacao_sem_site;
  lead.mensagem_gerada_sem_site = `Oi! Vi a ${lead.nome} no Google e notei que vocês não têm site ainda, só aparecem por aqui mesmo.\n\nIsso chamou minha atenção porque ${obs} — e dá pra fazer isso ficar bem simples, sem virar um projeto grande ou caro.\n\nJá ajudei alguns negócios parecidos com isso. Se fizer sentido, posso te mostrar uns exemplos e a gente conversa se topa, sem compromisso nenhum.`;

  lead.ollama_prompt = "Escreva apenas a palavra 'ok'.";
  return [{ json: lead }];
}

const lib = {
  abertura: [
    "Oi! Encontrei a [nome] no Google e dei uma olhada no site de vocês.",
    "Oi! Passei pelo site de vocês e uma coisa me chamou atenção.",
    "Oi! Estava pesquisando empresas da região e acabei chegando no site de vocês."
  ],
  contexto: [
    "Vi que vocês trabalham com [principal_servico].",
    "Acabei vendo que vocês atuam na área de [principal_servico].",
    "Pelo que vi no site, o foco de vocês é [principal_servico]."
  ],
  gancho: [
    "Enquanto olhava o site, teve um detalhe que me chamou atenção.",
    "Navegando por ele, encontrei algo que acho que vale mostrar.",
    "Vi uma coisa no site que pode estar atrapalhando sem vocês perceberem."
  ],
  impacto: [
    "No fim, quem está com pressa normalmente não insiste muito.",
    "Esse tipo de detalhe faz muita gente fechar a página antes de entrar em contato.",
    "Nessa hora muita gente acaba indo para outro resultado."
  ],
  cta: [
    "Se fizer sentido, posso te mostrar exatamente o que encontrei.",
    "Posso te explicar melhor o que vi.",
    "Se quiser, te mostro em dois minutos."
  ]
};

const r = (arr) => arr[Math.floor(Math.random() * arr.length)];

lead.b1_abertura = r(lib.abertura).replace('\[nome\]', lead.nome);
lead.b2_contexto = lead.principal_servico ? r(lib.contexto).replace('\[principal_servico\]', lead.principal_servico.toLowerCase()) : '';
lead.b3_gancho = r(lib.gancho);

const problema_principal = (lead.problemas_encontrados && lead.problemas_encontrados.length > 0) 
    ? lead.problemas_encontrados[0]
    : 'Algumas coisas poderiam estar melhores';

lead.b5_impacto = r(lib.impacto);
lead.b6_autoridade = "Trabalho justamente com esse tipo de análise para negócios locais.";
lead.b7_cta = r(lib.cta);

lead.ollama_prompt = `Você é um especialista em comunicação de WhatsApp no Brasil. Sua única tarefa é reescrever o problema técnico abaixo em terceira pessoa (falando do site do cliente) em UMA frase coloquial e natural (máximo de 2 frases) para que se encaixe no meio de uma conversa com o dono da empresa. Ex: 'O site não possui...' e nunca 'O nosso site não possui...'. Não use jargão técnico como SEO, viewport, meta description, alt tag, SSL, cache, DOM, HTML, tag.\n\nPROBLEMA ORIGINAL:\n"${problema_principal}"\n\nRetorne APENAS uma frase contendo a reescrita do problema. Não escreva nenhuma outra frase antes ou depois. Não adicione saudações, nem introduções.`;

return [{
  json: lead
}];

const lead = $('Selecionar Variaveis e Prompt').first().json;
const ollamaResp = $input.first().json;

if (!lead.tem_site || lead.site_inacessivel) {
  lead.mensagem_gerada = lead.mensagem_gerada_sem_site;
  lead.status = 'aguardando_aprovacao';
  return [{ json: lead }];
}

let b4_problema = ollamaResp.response ? ollamaResp.response.trim().replace(/^["']|["']$/g, '') : '';

let erros = [];
const wordCount = b4_problema.split(/\s+/).length;
if (wordCount > 40) erros.push(`Bloco 4 muito longo (${wordCount} palavras)`);

const frasesProibidas = ['trabalho', 'se quiser', 'posso te', 'aqui está', 'claro', 'olá', 'oi', 'tudo bem'];
const regexProibida = new RegExp(`\\b(${frasesProibidas.join('|')})\\b`, 'i');
if (b4_problema.match(regexProibida)) erros.push('Bloco 4 contém elementos típicos de outros blocos ou saudações');

const jargoes = ['seo', 'viewport', 'meta description', 'alt tag', 'ssl', 'https', 'cache', 'dom', 'html', 'tag'];
const regexJargoes = new RegExp(`\\b(${jargoes.join('|')})\\b`, 'i');
if (b4_problema.match(regexJargoes)) erros.push('Bloco 4 contém jargões técnicos');

const numFrases = (b4_problema.match(/[.!?]+(?=\s|$)/g) || []).length;
const contagemRealFrases = numFrases === 0 ? 1 : numFrases;
if (contagemRealFrases > 2) erros.push(`Bloco 4 tem mais de 2 frases (${contagemRealFrases} frases)`);

if (!b4_problema) erros.push('Bloco 4 vazio');

if (erros.length > 0) {
  lead.status = 'erro_copy';
  lead.erro_detalhe = erros.join(', ');
} else {
  const blocos = [
    lead.b1_abertura,
    lead.b2_contexto,
    lead.b3_gancho,
    b4_problema,
    lead.b5_impacto,
    lead.b6_autoridade,
    lead.b7_cta
  ];

  lead.mensagem_gerada = blocos.filter(b => b && b.trim() !== '').join(' ');
  lead.status = 'aguardando_aprovacao'; // Para teste manual mudar para 'aprovado'
}

return [{
  json: lead
}];

const inputItem = $input.first();
const lead = $('Montar e Validar Mensagem').first().json;

const isError = inputItem.json.error || (inputItem.json.statusCode && inputItem.json.statusCode >= 400);

if (isError) {
  lead.status = 'erro_envio';
  lead.erro_detalhe = inputItem.json.error ? inputItem.json.error.message : (inputItem.json.message || 'Erro HTTP');
} else {
  lead.status = 'enviado';
  lead.timestamp_envio = new Date().toISOString();
}

return [{
  json: lead
}];
